import React, { useState, useEffect } from 'react';
import { 
  Users, CreditCard, Settings, Bell, Home, User, Lock, Mail, LogOut, 
  Smartphone, Zap, ShieldCheck, CheckCircle2, ArrowLeft, ChevronRight, 
  Globe, CreditCard as CardIcon, Eye, Download, X, Upload, Trash2, Save,
  ShieldAlert, Landmark, Building, Menu
} from 'lucide-react';

const App = () => {
  const [userRole, setUserRole] = useState(null); 
  const [loginMode, setLoginMode] = useState('tenant'); 
  const [activeTab, setActiveTab] = useState('Dashboard');
  const [showPaymentSystem, setShowPaymentSystem] = useState(false);

  // --- Central Data Engine ---
  const [tenants, setTenants] = useState([
    { id: 1, name: 'Rajesh Kumar', room: 'A-101', status: 'Pending', amount: '12,500', date: 'N/A', phone: '+91 98765 43210', method: 'N/A', email: 'rajesh.k@example.com', joinDate: '12 Jan 2024' },
    { id: 2, name: 'Anita Sharma', room: 'B-204', status: 'Pending', amount: '15,000', date: 'N/A', phone: '+91 88776 65544', method: 'N/A', email: 'anita.s@example.com', joinDate: '05 Feb 2025' },
    { id: 3, name: 'Vikram Singh', room: 'C-302', status: 'Paid', amount: '10,000', date: '24 Mar 2026', phone: '+91 77665 44332', method: 'Debit Card', email: 'vikram.v@example.com', joinDate: '20 Nov 2023' },
  ]);

  const [notifications, setNotifications] = useState([
    { id: 1, title: 'Server Maintenance', desc: 'Portal will be down at 2 AM IST.', time: '2h ago', type: 'info' },
    { id: 2, title: 'New Tenant Request', desc: 'Room D-401 has a new applicant.', time: '5h ago', type: 'alert' }
  ]);

  const processTenantPayment = (method) => {
    const today = new Date().toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' });
    setTenants(prev => prev.map(t => t.id === 1 ? { ...t, status: 'Paid', date: today, method: method } : t));
    setNotifications(prev => [{
      id: Date.now(),
      title: 'Payment Received',
      desc: `₹12,500 from Rajesh (A-101) via ${method}`,
      time: 'Just now',
      type: 'success'
    }, ...prev]);
    setShowPaymentSystem(false);
  };

  // --- Auth Screen (Responsive) ---
  if (!userRole) {
    return (
      <div className="min-h-screen bg-[#0F172A] flex items-center justify-center p-4 md:p-6 font-sans">
        <div className="w-full max-w-4xl bg-white rounded-[2rem] md:rounded-[3rem] overflow-hidden shadow-2xl grid grid-cols-1 md:grid-cols-2">
          <div className="bg-slate-900 p-8 md:p-16 text-white flex flex-col justify-between hidden md:flex">
            <div className="flex items-center gap-3 italic font-black text-2xl">
              <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center text-white not-italic">H</div> Homely
            </div>
            <h1 className="text-4xl md:text-5xl font-black leading-tight italic">Your Home,<br/>Managed.<br/>Better.</h1>
            <p className="text-slate-500 font-bold uppercase tracking-widest text-[10px] italic">Version 4.0.2 Stable</p>
          </div>
          <div className="p-8 md:p-16 flex flex-col justify-center">
             <div className="md:hidden flex items-center gap-3 italic font-black text-xl mb-8">
              <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white not-italic text-sm">H</div> Homely
            </div>
            <div className="flex gap-2 p-1 bg-slate-100 rounded-2xl mb-8">
              <button onClick={() => setLoginMode('tenant')} className={`flex-1 py-3 md:py-4 rounded-xl text-[9px] md:text-[10px] font-black uppercase transition-all ${loginMode === 'tenant' ? 'bg-white text-indigo-600 shadow-xl' : 'text-slate-400'}`}>Resident</button>
              <button onClick={() => setLoginMode('admin')} className={`flex-1 py-3 md:py-4 rounded-xl text-[9px] md:text-[10px] font-black uppercase transition-all ${loginMode === 'admin' ? 'bg-white text-indigo-600 shadow-xl' : 'text-slate-400'}`}>Landlord</button>
            </div>
            <form onSubmit={(e) => {e.preventDefault(); setUserRole(loginMode);}} className="space-y-4">
              <input type="text" placeholder="ID Number / Mobile" className="w-full bg-slate-50 border-none rounded-2xl py-4 md:py-5 px-6 md:px-8 font-bold outline-none focus:ring-2 ring-indigo-500 transition-all" required />
              <input type="password" placeholder="Password" className="w-full bg-slate-50 border-none rounded-2xl py-4 md:py-5 px-6 md:px-8 font-bold outline-none focus:ring-2 ring-indigo-500 transition-all" required />
              <button className="w-full bg-slate-900 text-white font-black py-4 md:py-5 rounded-2xl uppercase tracking-[0.2em] text-[10px] shadow-2xl hover:bg-indigo-600 transition-all">Sign In</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return userRole === 'admin' ? (
    <AdminPortal tenants={tenants} notifications={notifications} activeTab={activeTab} setActiveTab={setActiveTab} logout={() => setUserRole(null)} />
  ) : (
    <TenantPortal tenant={tenants[0]} tenants={tenants} showPayment={showPaymentSystem} setShowPayment={setShowPaymentSystem} onPay={processTenantPayment} logout={() => setUserRole(null)} />
  );
};

// --- ADMIN PORTAL COMPONENTS ---
const AdminPortal = ({ tenants, notifications, activeTab, setActiveTab, logout }) => {
  const [profileOpen, setProfileOpen] = useState(false);
  const [selectedTenant, setSelectedTenant] = useState(null);
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const totalCollected = tenants.reduce((acc, t) => t.status === 'Paid' ? acc + parseInt(t.amount.replace(',','')) : acc, 0);
  const totalPending = tenants.reduce((acc, t) => t.status === 'Pending' ? acc + parseInt(t.amount.replace(',','')) : acc, 0);

  return (
    <div className="flex h-screen bg-[#F8FAFC]">
      {/* Responsive Sidebar */}
      <aside className={`fixed inset-y-0 left-0 z-50 w-72 bg-slate-900 text-white p-8 flex flex-col shrink-0 transition-transform md:relative md:translate-x-0 ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="flex items-center justify-between mb-12">
            <div className="flex items-center gap-3 font-black italic text-xl">
                <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white not-italic">H</div> Homely
            </div>
            <button onClick={() => setSidebarOpen(false)} className="md:hidden text-slate-400"><X/></button>
        </div>
        <nav className="space-y-2 flex-1">
          {['Dashboard', 'Tenants', 'Payments', 'Notifications', 'Settings'].map(tab => (
            <button key={tab} onClick={() => {setActiveTab(tab); setSidebarOpen(false);}} className={`w-full flex items-center gap-4 px-6 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-900/50' : 'text-slate-500 hover:text-white'}`}>
              {tab === 'Dashboard' && <Home size={18}/>}
              {tab === 'Tenants' && <Users size={18}/>}
              {tab === 'Payments' && <CreditCard size={18}/>}
              {tab === 'Notifications' && <Bell size={18}/>}
              {tab === 'Settings' && <Settings size={18}/>}
              {tab}
            </button>
          ))}
        </nav>
      </aside>

      <div className="flex-1 flex flex-col overflow-hidden">
        <header className="h-20 md:h-24 bg-white border-b px-6 md:px-12 flex items-center justify-between">
           <div className="flex items-center gap-4">
             <button onClick={() => setSidebarOpen(true)} className="md:hidden p-2 text-slate-600"><Menu/></button>
             <h2 className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">{activeTab}</h2>
           </div>
           <div className="relative">
              <button onClick={() => setProfileOpen(!profileOpen)} className="flex items-center gap-3 p-2 pr-4 md:pr-6 bg-slate-50 border rounded-2xl hover:bg-slate-100 transition-all">
                 <div className="w-8 h-8 md:w-10 md:h-10 bg-slate-900 text-white rounded-xl flex items-center justify-center font-black text-sm">AD</div>
                 <span className="text-[10px] font-black uppercase italic hidden sm:inline">Manager <ChevronRight size={12}/></span>
              </button>
              {profileOpen && (
                 <div className="absolute right-0 mt-4 w-48 md:w-52 bg-white rounded-2xl shadow-2xl border p-2 z-50">
                    <button onClick={() => {setActiveTab('Settings'); setProfileOpen(false);}} className="w-full flex items-center gap-3 p-3 md:p-4 text-[9px] md:text-[10px] font-black text-slate-600 hover:bg-slate-50 rounded-xl uppercase"><User size={14}/> Profile</button>
                    <button onClick={logout} className="w-full flex items-center gap-3 p-3 md:p-4 text-[9px] md:text-[10px] font-black text-red-500 hover:bg-red-50 rounded-xl uppercase border-t mt-2 pt-4"><LogOut size={14}/> Sign Out</button>
                 </div>
              )}
           </div>
        </header>

        <main className="flex-1 overflow-y-auto p-6 md:p-12">
          {activeTab === 'Dashboard' && (
            <div className="space-y-8 md:space-y-12 animate-in fade-in duration-500">
               <div className="grid grid-cols-1 md:grid-cols-3 gap-6 md:gap-8">
                  <div className="bg-white p-8 md:p-10 rounded-[2.5rem] md:rounded-[3rem] border shadow-sm flex justify-between items-center">
                      <div><p className="text-[9px] font-black text-slate-400 uppercase mb-2">Collected</p><h3 className="text-3xl md:text-4xl font-black italic text-emerald-600">₹{totalCollected.toLocaleString()}</h3></div>
                      <Landmark className="text-emerald-500/10" size={40}/>
                  </div>
                  <div className="bg-white p-8 md:p-10 rounded-[2.5rem] md:rounded-[3rem] border shadow-sm flex justify-between items-center">
                      <div><p className="text-[9px] font-black text-slate-400 uppercase mb-2">Pending</p><h3 className="text-3xl md:text-4xl font-black italic text-red-500">₹{totalPending.toLocaleString()}</h3></div>
                      <ShieldAlert className="text-red-500/10" size={40}/>
                  </div>
                  <div className="bg-indigo-600 p-8 md:p-10 rounded-[2.5rem] md:rounded-[3rem] shadow-2xl text-white">
                      <p className="text-[9px] font-black uppercase mb-2 text-indigo-200">System Health</p>
                      <h3 className="text-3xl md:text-4xl font-black italic flex items-center gap-3">Good <div className="w-3 h-3 bg-emerald-400 rounded-full animate-pulse"></div></h3>
                  </div>
               </div>

               <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 md:gap-12">
                  {/* Notifications */}
                  <div className="bg-white rounded-[2.5rem] md:rounded-[3.5rem] border shadow-sm p-8 md:p-10">
                     <h3 className="text-xs font-black uppercase mb-8 italic flex items-center gap-2">Recent Activity <span className="bg-indigo-100 text-indigo-600 px-3 py-1 rounded-full text-[9px]">{notifications.length}</span></h3>
                     <div className="space-y-4">
                        {notifications.map(n => (
                           <div key={n.id} className="flex gap-4 p-4 md:p-5 bg-slate-50 rounded-2xl border border-slate-100">
                              <div className={`w-1 h-10 md:h-12 rounded-full ${n.type === 'success' ? 'bg-emerald-400' : 'bg-indigo-400'}`}></div>
                              <div className="flex-1"><p className="text-[11px] md:text-xs font-black italic">{n.title}</p><p className="text-[9px] md:text-[10px] font-bold text-slate-400">{n.desc}</p></div>
                              <span className="text-[8px] font-black text-slate-300 uppercase">{n.time}</span>
                           </div>
                        ))}
                     </div>
                  </div>

                  {/* Table */}
                  <div className="bg-white rounded-[2.5rem] md:rounded-[3.5rem] border shadow-sm overflow-hidden flex flex-col">
                     <div className="p-8 md:p-10 pb-6"><h3 className="text-xs font-black uppercase italic">Recent Transactions</h3></div>
                     <div className="overflow-x-auto">
                        <table className="w-full text-left min-w-[400px]">
                           <thead className="bg-slate-50 text-[9px] font-black text-slate-400 uppercase"><tr className="border-y"><th className="px-10 py-4">Tenant</th><th className="px-10 py-4">Method</th><th className="px-10 py-4 text-right">Status</th></tr></thead>
                           <tbody>
                              {tenants.map(t => (
                                 <tr key={t.id} className="border-b border-slate-50 last:border-0">
                                    <td className="px-10 py-5 font-bold text-xs">{t.name}</td>
                                    <td className="px-10 py-5 font-black text-[9px] text-indigo-600 uppercase italic">{t.method}</td>
                                    <td className="px-10 py-5 text-right"><span className={`px-4 py-1 rounded-full text-[8px] font-black uppercase ${t.status === 'Paid' ? 'bg-emerald-100 text-emerald-600' : 'bg-red-100 text-red-600'}`}>{t.status}</span></td>
                                 </tr>
                              ))}
                           </tbody>
                        </table>
                     </div>
                  </div>
               </div>
            </div>
          )}

          {activeTab === 'Tenants' && (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-8 animate-in slide-in-from-bottom-8">
               {tenants.map(t => (
                  <div key={t.id} className="bg-white p-8 md:p-10 rounded-[2.5rem] md:rounded-[3rem] border shadow-sm group hover:border-indigo-600 transition-all flex flex-col">
                     <div className="w-14 h-14 md:w-16 md:h-16 bg-slate-50 rounded-2xl flex items-center justify-center font-black text-slate-300 text-xl mb-6 group-hover:bg-indigo-600 group-hover:text-white transition-all">{t.name[0]}</div>
                     <h4 className="text-xl md:text-2xl font-black italic mb-1">{t.name}</h4>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-8">{t.room}</p>
                     <button onClick={() => setSelectedTenant(t)} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-indigo-600 transition-all flex items-center justify-center gap-2 shadow-xl shadow-indigo-100 mt-auto"><Eye size={16}/> View Records</button>
                  </div>
               ))}
            </div>
          )}
          
          {/* Mobile Overlay for Notifications/Settings could be added here */}
        </main>
      </div>

      {/* Modal - Fully Responsive */}
      {selectedTenant && (
        <div className="fixed inset-0 z-[100] bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-4 md:p-6">
           <div className="bg-white w-full max-w-lg rounded-[2.5rem] md:rounded-[3.5rem] p-8 md:p-12 relative shadow-2xl animate-in zoom-in-95">
              <button onClick={() => setSelectedTenant(null)} className="absolute top-8 right-8 text-slate-300 hover:text-slate-900"><X size={24}/></button>
              <div className="flex items-center gap-6 md:gap-8 mb-10 md:mb-12">
                 <div className="w-20 h-20 md:w-24 md:h-24 bg-indigo-600 text-white rounded-[1.5rem] md:rounded-[2rem] flex items-center justify-center text-3xl md:text-4xl font-black italic">{selectedTenant.name[0]}</div>
                 <div><h4 className="text-2xl md:text-3xl font-black italic">{selectedTenant.name}</h4><p className="text-[11px] md:text-sm font-bold text-slate-400 uppercase tracking-widest">{selectedTenant.room}</p></div>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 md:gap-6">
                 <div className="p-4 md:p-5 bg-slate-50 rounded-2xl"><p className="text-[8px] md:text-[9px] font-black text-slate-400 uppercase mb-1 md:2">Phone</p><p className="text-xs md:text-sm font-black italic">{selectedTenant.phone}</p></div>
                 <div className="p-4 md:p-5 bg-slate-50 rounded-2xl"><p className="text-[8px] md:text-[9px] font-black text-slate-400 uppercase mb-1 md:2">Registration</p><p className="text-xs md:text-sm font-black italic">{selectedTenant.joinDate}</p></div>
                 <div className="p-4 md:p-5 bg-slate-50 rounded-2xl sm:col-span-2"><p className="text-[8px] md:text-[9px] font-black text-slate-400 uppercase mb-1 md:2">Private Email</p><p className="text-xs md:text-sm font-black italic">{selectedTenant.email}</p></div>
              </div>
              <button className="w-full mt-8 md:mt-10 py-4 md:py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest">Update Resident Info</button>
           </div>
        </div>
      )}
    </div>
  );
};

// --- TENANT PORTAL COMPONENTS ---
const TenantPortal = ({ tenant, tenants, showPayment, setShowPayment, onPay, logout }) => {
  const [activeTab, setActiveTab] = useState('Overview');
  const [profileOpen, setProfileOpen] = useState(false);

  return (
    <div className="min-h-screen bg-[#FDFDFD] flex flex-col font-sans">
      <header className="h-20 md:h-24 bg-white border-b px-6 md:px-12 flex items-center justify-between sticky top-0 z-50">
         <div className="flex items-center gap-2 md:gap-3 italic font-black text-lg md:text-xl text-indigo-600">
            <div className="w-8 h-8 md:w-10 md:h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white italic not-italic">H</div> MyHome
         </div>
         <nav className="hidden md:flex gap-10">
            {['Overview', 'Documents', 'History', 'Settings'].map(t => (
               <button key={t} onClick={() => setActiveTab(t)} className={`text-[10px] font-black uppercase tracking-widest pb-1 border-b-2 transition-all ${activeTab === t ? 'text-indigo-600 border-indigo-600' : 'text-slate-300 border-transparent'}`}>{t}</button>
            ))}
         </nav>
         <div className="relative">
            <button onClick={() => setProfileOpen(!profileOpen)} className="w-10 h-10 md:w-12 md:h-12 bg-slate-900 text-white rounded-xl md:rounded-2xl flex items-center justify-center font-black shadow-xl hover:scale-105 transition-all text-sm">RK</button>
            {profileOpen && (
               <div className="absolute right-0 mt-4 w-48 md:w-52 bg-white rounded-2xl shadow-2xl border p-2 z-[60]">
                  <button onClick={() => {setActiveTab('Settings'); setProfileOpen(false);}} className="w-full flex items-center gap-3 p-3 md:p-4 text-[9px] md:text-[10px] font-black text-slate-600 hover:bg-slate-50 rounded-xl uppercase"><User size={16}/> Profile</button>
                  <button onClick={logout} className="w-full flex items-center gap-3 p-3 md:p-4 text-[9px] md:text-[10px] font-black text-red-500 hover:bg-red-50 rounded-xl uppercase border-t mt-2 pt-4"><LogOut size={16}/> Sign Out</button>
               </div>
            )}
         </div>
      </header>

      {/* Mobile Navigation */}
      <nav className="md:hidden flex justify-around p-4 bg-white border-b sticky top-20 z-40">
        {['Overview', 'Documents', 'Settings'].map(t => (
            <button key={t} onClick={() => setActiveTab(t)} className={`text-[9px] font-black uppercase tracking-widest pb-1 border-b-2 transition-all ${activeTab === t ? 'text-indigo-600 border-indigo-600' : 'text-slate-300 border-transparent'}`}>{t}</button>
        ))}
      </nav>

      <main className="p-6 md:p-12 max-w-6xl mx-auto w-full flex-1">
        {activeTab === 'Overview' && (
           <div className="space-y-8 md:space-y-12 animate-in slide-in-from-bottom-8">
              <div className="bg-indigo-600 rounded-[2.5rem] md:rounded-[3.5rem] p-8 md:p-16 text-white shadow-2xl relative overflow-hidden group">
                 <div className="absolute top-[-20%] right-[-10%] w-64 h-64 md:w-96 md:h-96 bg-white/10 rounded-full blur-3xl"></div>
                 <p className="text-[9px] md:text-[10px] font-black uppercase text-indigo-200 mb-4 tracking-widest italic">Current Bill • {tenant.room}</p>
                 <h2 className="text-5xl md:text-7xl font-black tracking-tighter italic mb-10 md:mb-12">₹{tenant.amount}</h2>
                 <div className="flex gap-4">
                    {tenant.status === 'Paid' ? (
                        <div className="flex items-center gap-3 bg-white/20 px-6 md:px-8 py-3 md:py-4 rounded-xl md:rounded-2xl font-black uppercase text-[10px] md:text-xs"><CheckCircle2 size={20}/> Payment Confirmed</div>
                    ) : (
                        <button onClick={() => setShowPayment(true)} className="bg-white text-indigo-600 px-8 md:px-10 py-4 md:py-5 rounded-xl md:rounded-2xl font-black uppercase text-[10px] md:text-xs shadow-2xl hover:scale-105 transition-all">Pay Rent Now</button>
                    )}
                 </div>
              </div>
           </div>
        )}

        {activeTab === 'Documents' && (
           <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-8 animate-in fade-in">
              <h3 className="text-2xl md:text-3xl font-black italic uppercase col-span-full mb-4">Your Archive</h3>
              {['Lease_Contract_2026.pdf', 'Receipt_Feb_2026.pdf'].map(doc => (
                 <div key={doc} className="bg-white p-8 md:p-10 rounded-[2.5rem] md:rounded-[3rem] border shadow-sm group hover:bg-indigo-600 hover:text-white transition-all">
                    <div className="w-14 h-14 md:w-16 md:h-16 bg-slate-50 rounded-2xl flex items-center justify-center mb-6 group-hover:bg-white/10"><Download className="text-indigo-600 group-hover:text-white" size={24}/></div>
                    <p className="text-lg md:text-xl font-black italic mb-2">{doc}</p>
                    <p className="text-[9px] font-bold text-slate-300 uppercase mb-8 group-hover:text-indigo-200">2.4 MB • PDF Document</p>
                    <button className="text-[9px] font-black uppercase tracking-widest group-hover:text-white border-b-2 border-indigo-100 group-hover:border-white/20 pb-1">Download</button>
                 </div>
              ))}
           </div>
        )}
      </main>

      {/* Payment Overlay - Mobile Optimized */}
      {showPayment && (
        <div className="fixed inset-0 z-[100] bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-4 md:p-6">
           <div className="bg-white w-full max-w-4xl rounded-[2.5rem] md:rounded-[4rem] overflow-hidden shadow-2xl grid grid-cols-1 md:grid-cols-5 animate-in zoom-in-95 duration-300 max-h-[90vh] overflow-y-auto">
              <div className="md:col-span-2 bg-slate-50 p-8 md:p-12 border-b md:border-b-0 md:border-r flex flex-col justify-between">
                 <div>
                    <button onClick={() => setShowPayment(false)} className="flex items-center gap-2 text-[10px] font-black text-slate-300 uppercase mb-8 md:12"><ArrowLeft size={16}/> Back</button>
                    <h4 className="text-3xl md:text-4xl font-black italic uppercase mb-2">Checkout</h4>
                    <p className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest italic">Property: Homely Square A-101</p>
                 </div>
                 <div className="pt-8 mt-8 border-t border-slate-200">
                    <p className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase mb-2">Total Amount</p>
                    <p className="text-4xl md:text-5xl font-black italic text-indigo-600">₹12,500</p>
                 </div>
              </div>
              <div className="md:col-span-3 p-8 md:p-16 flex flex-col justify-center space-y-6 md:space-y-8">
                 <div className="grid grid-cols-2 gap-4">
                    <button className="p-4 md:p-6 border-2 border-indigo-600 rounded-2xl md:rounded-3xl bg-indigo-50 flex flex-col items-center gap-4">
                       <Smartphone className="text-indigo-600" size={28}/>
                       <span className="text-[9px] md:text-[10px] font-black uppercase tracking-widest">UPI</span>
                    </button>
                    <button className="p-4 md:p-6 border-2 border-slate-100 rounded-2xl md:rounded-3xl hover:border-indigo-600 transition-all flex flex-col items-center gap-4 text-slate-400 hover:text-indigo-600">
                       <CardIcon size={28}/>
                       <span className="text-[9px] md:text-[10px] font-black uppercase tracking-widest">Card</span>
                    </button>
                 </div>
                 <button onClick={() => onPay('UPI')} className="w-full bg-slate-900 text-white py-4 md:py-6 rounded-2xl md:rounded-3xl font-black uppercase text-[10px] md:text-[11px] tracking-[0.2em] md:tracking-[0.4em] shadow-2xl hover:bg-indigo-600 transition-all">Pay ₹12,500</button>
                 <p className="text-center text-[8px] md:text-[9px] font-black text-slate-300 uppercase flex items-center justify-center gap-2"><ShieldCheck size={14}/> Secure Transaction</p>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;
